VALUES
  ('heelevel3-6e11b43e-moex-00212', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-111-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '關於訴願決定之敘述，下列何者錯誤？', '["訴願決定確定後，就該事件，有拘束原處分機關之效力", "訴願決定確定後，就受委託行使公權力之事件，受委託行使公權力之團體或個人受其拘束", "原行政處分經撤銷後，原行政處分機關須重為處分者，應依訴願決定意旨為之，並將處理情形 以書面告知受理訴願機關", "內政部之行政處分，經行政院訴願決定撤銷，內政部為確認其處分是否合法，得向行政法院提 起行政訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00213', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-111-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '關於行政訴訟法上停止執行制度之敘述，下列何者錯誤？', '["行政法院認原處分之執行，將發生難以回復之損害，且有急迫情事者，得裁定停止執行", "訴訟繫屬中行政處分以不停止執行為原則", "行政法院裁定停止執行前，原處分機關已依職權停止執行者，應為駁回聲請之裁定", "於行政訴訟起訴前，行政法院不得依聲請裁定停止執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:24+00:00", "source_pdf_sha1": "b4a31a26c6f1", "answer_pdf_sha1": "98cbeae447c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "327", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
